class Editor:
    def __init__(
        self,
        editor: str | None = None,
        env: cabc.Mapping[str, str] | None = None,
        require_save: bool = True,
        extension: str = ".txt",
        process_priority: str | None = None,
    ) -> None:
        self.editor = editor
        self.env = env
        self.require_save = require_save
        self.extension = extension
        self.process_priority = process_priority

    def get_editor(self) -> str:
        if self.editor is not None:
            return self.editor
        for key in "VISUAL", "EDITOR":
            rv = os.environ.get(key)
            if rv:
                return rv
        if WIN:
            return "notepad"
        for editor in "sensible-editor", "vim", "nano":
            if os.system(f"which {editor} >/dev/null 2>&1") == 0:
                return editor
        return "vi"

    def _set_process_priority(self, pid: int) -> None:
        priority = self.process_priority

        if priority is None:
            return

        try:
            if WIN:
                priority_classes = {
                    "low": 0x00000040,  # IDLE_PRIORITY_CLASS
                    "below_normal": 0x00004000,  # BELOW_NORMAL_PRIORITY_CLASS
                    "normal": 0x00000020,  # NORMAL_PRIORITY_CLASS
                    "above_normal": 0x00008000,  # ABOVE_NORMAL_PRIORITY_CLASS
                    "high": 0x00000080,  # HIGH_PRIORITY_CLASS
                }
                priority_class = priority_classes.get(priority)

                if priority_class is None:
                    return

                import ctypes

                PROCESS_SET_INFORMATION = 0x0200
                handle = ctypes.windll.kernel32.OpenProcess(  # type: ignore[attr-defined]
                    PROCESS_SET_INFORMATION, False, pid
                )

                if handle:
                    try:
                        ctypes.windll.kernel32.SetPriorityClass(  # type: ignore[attr-defined]
                            handle, priority_class
                        )
                    finally:
                        ctypes.windll.kernel32.CloseHandle(handle)  # type: ignore[attr-defined]
            else:
                niceness = {
                    "low": 10,
                    "below_normal": 5,
                    "normal": 0,
                    "above_normal": -5,
                    "high": -10,
                }.get(priority)

                if niceness is None:
                    return

                os.setpriority(os.PRIO_PROCESS, pid, niceness)
        except Exception:
            pass

    def edit_files(self, filenames: cabc.Iterable[str]) -> None:
        import subprocess

        editor = self.get_editor()
        environ: dict[str, str] | None = None

        if self.env:
            environ = os.environ.copy()
            environ.update(self.env)

        exc_filename = " ".join(f'"{filename}"' for filename in filenames)

        try:
            c = subprocess.Popen(f"{editor} {exc_filename}", env=environ, shell=True)
            self._set_process_priority(c.pid)
            exit_code = c.wait()
            if exit_code != 0:
                raise ClickException(
                    _("{editor}: Editing failed").format(editor=editor)
                )
        except OSError as e:
            raise ClickException(
                _("{editor}: Editing failed: {e}").format(editor=editor, e=e)
            ) from e

